/// {@category Controllers}
library;

// Dart imports:
import 'dart:async';

// Package imports:
import 'package:fimber/fimber.dart';
import 'package:freezed_annotation/freezed_annotation.dart';
import 'package:package_info_plus/package_info_plus.dart';
import 'package:pub_semver/pub_semver.dart';
import 'package:riverpod_annotation/riverpod_annotation.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/clients/static_file_client.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/result.dart';
import 'package:baseball_detector_flutter/utils/platform.dart';

part 'version_controller.freezed.dart';
part 'version_controller.g.dart';

abstract class VersionControllerHandlers {
  void onNewVersionAvailable();

  void onNewVersionRequired();

  void onNewVersionRequirementWithdrawn();
}

@freezed
abstract class UpdateInfo with _$UpdateInfo {
  const factory UpdateInfo({
    required String current,
    required String required,
    required String latest,
  }) = _UpdateInfo;
}

@Riverpod(keepAlive: true)
class VersionController extends _$VersionController {
  static final _logger = FimberLog('VersionController');
  static const _interval = Duration(minutes: 5);
  static late VersionControllerHandlers _handlers;
  static bool _isUpdateNotified = false;
  static bool _isUpdateForced = false;
  static Timer? _timer;

  bool _mounted = true;
  final _client = StaticFileClient();

  static void registerHandlers(VersionControllerHandlers handlers) {
    _handlers = handlers;
  }

  static void reset() {
    _isUpdateNotified = false;
    _isUpdateForced = false;
  }

  @override
  AsyncValue<Result<Failure, UpdateInfo>> build() {
    _mounted = true;
    ref.onDispose(() => _mounted = false);

    if (_timer != null) {
      // reload and reset timer
      startObserving(true);
    } else {
      // reload
      _updateInfo();
    }
    return const AsyncValue.loading();
  }

  Future<void> _updateInfo() async {
    state = const AsyncValue.loading();
    final res = await _client.fetchVersionInfo();
    if (!res.hasRight) {
      if (_mounted) {
        state = AsyncValue.data(Left(res.left));
      }
      return;
    }
    final platform = isAndroid
        ? res.right.android
        : isIos
            ? res.right.ios
            : throw Exception('unsupported platform');

    final packageInfo = await PackageInfo.fromPlatform();
    final currentVersion = _parseVersion(
        'current', '${packageInfo.version}+${packageInfo.buildNumber}');
    if (currentVersion == null) {
      return;
    }

    final requiredVersion = _parseVersion('required', platform.required);
    final latestVersion = _parseVersion('latest', platform.latest);
    if (_mounted) {
      state = AsyncValue.data(Right(UpdateInfo(
        current: currentVersion.toString(),
        required: (requiredVersion ?? currentVersion).toString(),
        latest: (latestVersion ?? currentVersion).toString(),
      )));
    }

    if (requiredVersion != null) {
      if (!_isUpdateForced && requiredVersion > currentVersion) {
        _isUpdateForced = true;
        stopObserving();
        _handlers.onNewVersionRequired();
        return;
      }
      if (_isUpdateForced && requiredVersion <= currentVersion) {
        reset();
        _handlers.onNewVersionRequirementWithdrawn();
        return;
      }
    }

    if (latestVersion != null &&
        !_isUpdateForced &&
        !_isUpdateNotified &&
        latestVersion > currentVersion) {
      _isUpdateNotified = true;
      _handlers.onNewVersionAvailable();
      return;
    }
  }

  Version? _parseVersion(String type, String? source) {
    try {
      return source != null ? Version.parse(source) : null;
    } catch (e, stackTrace) {
      _logger.e('failed to parse $type version', ex: e, stacktrace: stackTrace);
      return null;
    }
  }

  Future<void> startObserving([bool refreshImmediately = true]) async {
    stopObserving();
    if (!_isUpdateForced) {
      _timer = Timer.periodic(_interval, (_) => _updateInfo());
    }
    if (refreshImmediately) {
      await _updateInfo();
    }
  }

  void stopObserving() {
    _timer?.cancel();
    _timer = null;
  }
}

