   804→                      closeMenu();
   805→                    }}
   806→                  >
   807→                    {translate('item_distribution')}
   808→                  </MenuItem>
   809→                  <MenuItem
   810→                    disabled={!team.teamPlan}
   811→                    onClick={() => {
   812→                      setEditCurrentOrPreviousTeamPlanModalParam({
   813→                        isOpen: true,
   814→                        team,
   815→                        title: editCurrentOrPreviousTeamPlanModalTitle,
   816→                      });
   817→                      closeMenu();
   818→                    }}
   819→                  >
   820→                    {editCurrentOrPreviousTeamPlanModalTitle}
   821→                  </MenuItem>
   822→                  {team.nextTeamPlan ? (
   823→                    <MenuItem
   824→                      onClick={() => {
   825→                        setEditOrDeleteNextTeamPlanModalParam({
   826→                          isOpen: true,
   827→                          team,
   828→                        });
   829→                        closeMenu();
   830→                      }}
   831→                    >
   832→                      {translate('edit_or_delete_next_team_plan')}
   833→                    </MenuItem>
   834→                  ) : (
   835→                    <MenuItem
   836→                      onClick={() => {
   837→                        setCreateTeamPlanModalParam({
   838→                          isOpen: true,
   839→                          team,
   840→                          title: createTeamPlanModalTitle,
   841→                        });
   842→                        closeMenu();
   843→                      }}
   844→                    >
   845→                      {createTeamPlanModalTitle}
   846→                    </MenuItem>
   847→                  )}
   848→                  <MenuItem
   849→                    onClick={() => {
   850→                      dispatch(
   851→                        userDataActions.setCurrentTeam({
   852→                          teamId: team.id,
   853→                        }),
   854→                      );
   855→
   856→                      services.localStorage.setCurrentTeamId(
   857→                        currentUser.id,
   858→                        team.id,
   859→                      );
   860→
   861→                      enqueueSnackbar({
   862→                        variant: 'success',
   863→                        message: translate('snackbar_change_current_team'),
   864→                      });
   865→
   866→                      closeMenu();
   867→                    }}
   868→                  >
   869→                    {translate('switch_team')}
   870→                  </MenuItem>
   871→                </>
   872→              ) : (
   873→                <></>
   874→              )}
   875→            </>
   876→          );
   877→        })()
   878→      )}
   879→    </Menu>
   880→  );
   881→
   882→  return (
   883→    // mbはFABのため
   884→    <Container sx={{ position: 'relative', mb: 10 }}>
   885→      <TeamCreationModal
   886→        param={teamCreationParam}
   887→        setParam={setTeamCreationParam}
   888→        isOpen={isCreationModalOpen}
   889→        setIsOpen={setIsCreationModalOpen}
   890→        onSuccess={() => {
   891→          setConditions({
   892→            ...conditions,
   893→            searchTrigger: new Date(),
   894→          });
   895→        }}
   896→      />
   897→      <EditCurrentOrPreviousTeamPlanModal
   898→        teamId={editCurrentOrPreviousTeamPlanModalParam.team?.id ?? null}
   899→        teamPlan={
   900→          editCurrentOrPreviousTeamPlanModalParam.team?.teamPlan ?? null
   901→        }
   902→        title={editCurrentOrPreviousTeamPlanModalParam.title}
   903→        isOpen={editCurrentOrPreviousTeamPlanModalParam.isOpen}
   904→        setIsOpen={(isOpen) =>
   905→          setEditCurrentOrPreviousTeamPlanModalParam((current) => ({
   906→            ...current,
   907→            isOpen: isOpen as boolean,
   908→          }))
   909→        }
   910→        onSuccess={getTeams}
   911→      />
   912→      <CreateTeamPlanModal
   913→        teamId={createTeamPlanModalParam.team?.id ?? null}
   914→        defaultDate={createTeamPlanModalParam.team?.teamPlan?.endDate ?? null}
   915→        title={createTeamPlanModalParam.title}
   916→        isOpen={createTeamPlanModalParam.isOpen}
   917→        setIsOpen={(isOpen) =>
   918→          setCreateTeamPlanModalParam((current) => ({
   919→            ...current,
   920→            isOpen: isOpen as boolean,
   921→          }))
   922→        }
   923→        onSuccess={getTeams}
   924→      />
   925→      <EditOrDeleteNextTeamPlanModal
   926→        teamId={editOrDeleteNextTeamPlanModalParam.team?.id ?? null}
   927→        teamPlan={editOrDeleteNextTeamPlanModalParam.team?.nextTeamPlan ?? null}
   928→        isOpen={editOrDeleteNextTeamPlanModalParam.isOpen}
   929→        setIsOpen={(isOpen) =>
   930→          setEditOrDeleteNextTeamPlanModalParam((current) => ({
   931→            ...current,
