   961→          {
   962→            name: translate(
   963→              PAGE_INFO.SUPER_ADMIN_TEAMS.name as keyof typeof translate,
   964→            ),
   965→            link: PAGE_INFO.SUPER_ADMIN_TEAMS.href(),
   966→          },
   967→        ]}
   968→      />
   969→      <Typography variant="h1">{translate('all_teams')}</Typography>
   970→      <Divider sx={{ mt: 1, mb: 5 }} />
   971→
   972→      <Card sx={{ backgroundColor: 'white', p: 2 }}>
   973→        {buildSearchAndFilterArea()}
   974→
   975→        {loadError ? (
   976→          <CriticalError error={loadError} />
   977→        ) : (
   978→          <>
   979→            <Box sx={{ mb: 2, mt: 2 }}>
   980→              <Stack direction="row" spacing={2}>
   981→                <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
   982→                  <Box
   983→                    sx={{
   984→                      width: 20,
   985→                      height: 20,
   986→                      backgroundColor: 'gray',
   987→                      border: '1px solid #ccc',
   988→                    }}
   989→                  />
   990→                  <Typography variant="body2">
   991→                    {translate('team_list_legend_deletion_scheduled')}
   992→                  </Typography>
   993→                </Box>
