   995→                  <Box
   996→                    sx={{
   997→                      width: 20,
   998→                      height: 20,
   999→                      backgroundColor: '#fff3e0',
  1000→                      border: '1px solid #ccc',
  1001→                    }}
  1002→                  />
  1003→                  <Typography variant="body2">
  1004→                    {translate('team_list_legend_no_quota')}
