  1008→            </Box>
  1009→            <TableContainer component={Paper}>
  1010→              <Table
  1011→                sx={{
  1012→                  tableLayout: 'fixed',
  1013→                  '.MuiTableCell-root': { overflowWrap: 'anywhere' },
  1014→                }}
  1015→              >
  1016→                <TableHead>
  1017→                  <TableRow>
