  1034→          </>
  1035→        )}
  1036→
  1037→        <CommonPagination
  1038→          user={currentUser}
  1039→          numberOfTotalItems={numberOfTotalItems}
  1040→          commonPaginationData={{
  1041→            currentPage: conditions.currentPage,
  1042→            rowsPerPage: conditions.rowsPerPage,
  1043→          }}
  1044→          onChange={(data) => {
  1045→            updateQueryParameters({
  1046→              ...conditions,
  1047→              ...data,
  1048→            });
  1049→          }}
  1050→        />
  1051→      </Card>
  1052→
  1053→      {hasSuperUserWriteAccess && (
  1054→        <FloatingButton
  1055→          icon={<PersonAddAlt />}
  1056→          title={translate('create_new_team')}
  1057→          onClick={() => setIsCreationModalOpen(true)}
  1058→        />
  1059→      )}
  1060→    </Container>
  1061→  );
  1062→}
  1063→
  1064→export default function Page() {
  1065→  const currentUser = useSelector((state) => state.user.me);
  1066→  const currentTeam = useSelector((state) => state.user.currentTeam);
  1067→  return (
