  Widget _buildExpirySection(
    BuildContext context,
    ThemeData theme,
    ValueNotifier<TeamSearchFilterParameters> localParams,
  ) {
    final nowDateTime = DateTime.now();
    final now = DateTime(nowDateTime.year, nowDateTime.month, nowDateTime.day);
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Text(
          context.l10n.super_admin_team_filter__expiry,
          style: theme.textTheme.titleSmall,
        ),
        const Gap(12),
        Wrap(
          spacing: 8,
          runSpacing: 8,
          children: [
            FilterChip(
              label: Text(context.l10n.super_admin_team_filter__all),
              selected: localParams.value.teamPlanEndDateFrom == null &&
                  localParams.value.teamPlanEndDateTo == null,
              onSelected: (_) {
                localParams.value = localParams.value.copyWith(
                  teamPlanEndDateFrom: null,
                  teamPlanEndDateTo: null,
                );
              },
            ),
            FilterChip(
              label: Text(context.l10n.super_admin_team_filter__expiry_1week),
              selected: _isExpiryFilterSelected(
                localParams.value,
                now,
                now.add(const Duration(days: 7)),
              ),
              onSelected: (_) {
                localParams.value = localParams.value.copyWith(
                  teamPlanEndDateFrom: now,
                  teamPlanEndDateTo: now.add(const Duration(days: 7)),
                );
              },
            ),
            FilterChip(
              label: Text(context.l10n.super_admin_team_filter__expiry_2weeks),
              selected: _isExpiryFilterSelected(
                localParams.value,
                now,
                now.add(const Duration(days: 14)),
              ),
              onSelected: (_) {
                localParams.value = localParams.value.copyWith(
                  teamPlanEndDateFrom: now,
                  teamPlanEndDateTo: now.add(const Duration(days: 14)),
                );
              },
            ),
          ],
        ),
        if (localParams.value.orderBy ==
                TeamSearchRequestOrderBy.teamPlanEndDate ||
            localParams.value.teamPlanEndDateFrom != null ||
            localParams.value.teamPlanEndDateTo != null) ...[
          const Gap(12),
          SwitchListTile(
            title:
                Text(context.l10n.super_admin_team_filter__include_next_plan),
            value: localParams.value.extendToNextTeamPlan ?? false,
            onChanged: (value) {
              localParams.value = localParams.value.copyWith(
                extendToNextTeamPlan: value,
              );
            },
            contentPadding: EdgeInsets.zero,
            dense: true,
          ),
        ],
      ],
    );
  }

  bool _isExpiryFilterSelected(
    TeamSearchFilterParameters params,
    DateTime from,
    DateTime to,
  ) {
    if (params.teamPlanEndDateFrom == null ||
        params.teamPlanEndDateTo == null) {
      return false;
    }
    // 日付のみで比較（時刻を無視）
    final fromDate = params.teamPlanEndDateFrom!;
    final toDate = params.teamPlanEndDateTo!;
    return fromDate.year == from.year &&
        fromDate.month == from.month &&
        fromDate.day == from.day &&
        toDate.year == to.year &&
        toDate.month == to.month &&
        toDate.day == to.day;
  }
}

