import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:gap/gap.dart';
import 'package:intl/intl.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/team.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';

/// A widget that displays a team item in the super admin team list.
class SuperAdminTeamListItem extends HookWidget {
  const SuperAdminTeamListItem({
    required this.team,
    required this.isSelected,
    required this.onTap,
    super.key,
  });

  final Team team;
  final bool isSelected;
  final VoidCallback onTap;

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);
    final textTheme = theme.textTheme;
    final colorScheme = theme.colorScheme;
    final isExpanded = useState(false);

    return Card(
      margin: const EdgeInsets.symmetric(horizontal: 16, vertical: 8),
      elevation: isSelected ? 4 : 1,
      shape: RoundedRectangleBorder(
        borderRadius: BorderRadius.circular(12),
        side: isSelected
            ? BorderSide(color: colorScheme.primary, width: 2)
            : BorderSide.none,
      ),
      child: InkWell(
        onTap: onTap,
        borderRadius: BorderRadius.circular(12),
        child: Padding(
          padding: const EdgeInsets.all(16),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Row(
                children: [
                  Expanded(
                    child: Text(
                      team.name ?? '',
                      style: textTheme.titleMedium?.copyWith(
                        fontWeight: FontWeight.bold,
                        color: isSelected ? colorScheme.primary : null,
                      ),
                      maxLines: 1,
                      overflow: TextOverflow.ellipsis,
                    ),
                  ),
                  if (isSelected) ...[
                    const Gap(8),
                    Icon(
                      Icons.check_circle,
                      color: colorScheme.primary,
                      size: 20,
                    ),
                  ],
                ],
              ),
              const Gap(8),
              // 基本情報
              _buildBasicInfo(context, textTheme, colorScheme),
              // プラン情報（簡易版）
              const Gap(8),
              _buildPlanSummary(context, textTheme, colorScheme),
              // 展開/折りたたみボタン
              const Gap(8),
              InkWell(
                onTap: () => isExpanded.value = !isExpanded.value,
                child: Row(
                  mainAxisAlignment: MainAxisAlignment.center,
                  children: [
                    Text(
                      isExpanded.value
                          ? context.l10n.super_admin_team_item__show_less
                          : context.l10n.super_admin_team_item__show_more,
                      style: textTheme.bodySmall?.copyWith(
                        color: colorScheme.primary,
                      ),
                    ),
                    Icon(
                      isExpanded.value
                          ? Icons.keyboard_arrow_up
                          : Icons.keyboard_arrow_down,
                      color: colorScheme.primary,
                      size: 20,
                    ),
                  ],
                ),
              ),
              // 詳細情報（折りたたみ）
              if (isExpanded.value) ...[
                const Gap(12),
                const Divider(),
                const Gap(12),
                _buildDetailedInfo(context, textTheme, colorScheme),
              ],
            ],
          ),
        ),
      ),
    );
  }

  Widget _buildBasicInfo(
    BuildContext context,
    TextTheme textTheme,
    ColorScheme colorScheme,
  ) {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Text(
          'ID: ${team.id ?? ''}',
          style: textTheme.bodySmall?.copyWith(
            color: colorScheme.onSurfaceVariant,
          ),
        ),
        if (team.ownerEmail != null) ...[
          const Gap(4),
          Text(
            '${context.l10n.super_admin_team_item__owner}: ${team.ownerEmail}',
            style: textTheme.bodySmall?.copyWith(
              color: colorScheme.onSurfaceVariant,
            ),
          ),
        ],
      ],
    );
  }

  Widget _buildPlanSummary(
    BuildContext context,
    TextTheme textTheme,
    ColorScheme colorScheme,
  ) {
    final currentPlan = team.teamPlan;
    final planName = currentPlan?.plan?.name ??
        context.l10n.super_admin_team_item__no_plan;
    final isPaid = currentPlan?.plan?.isPaid ?? false;

    return Row(
      children: [
        Text(
          isPaid ? '💲' : '🆓',
          style: textTheme.bodyMedium,
        ),
        const Gap(4),
        Expanded(
          child: Text(
            planName,
            style: textTheme.bodyMedium?.copyWith(
              color: colorScheme.onSurface,
            ),
            maxLines: 1,
            overflow: TextOverflow.ellipsis,
          ),
        ),
      ],
    );
  }

  Widget _buildDetailedInfo(
    BuildContext context,
    TextTheme textTheme,
    ColorScheme colorScheme,
  ) {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        // 次期プラン情報
        if (team.nextTeamPlan != null) ...[
          Text(
            context.l10n.super_admin_team_item__next_plan,
            style: textTheme.titleSmall?.copyWith(
              color: colorScheme.secondary,
            ),
          ),
          const Gap(4),
          Row(
            children: [
              Text(
                team.nextTeamPlan!.plan?.isPaid ?? false ? '💲' : '🆓',
                style: textTheme.bodySmall,
              ),
              const Gap(4),
              Text(
                team.nextTeamPlan!.plan?.name ?? '-',
                style: textTheme.bodySmall?.copyWith(
                  color: colorScheme.secondary,
                ),
              ),
            ],
          ),
          const Gap(12),
        ],
        // 使用状況
        _buildUsageInfo(context, textTheme, colorScheme),
        const Gap(12),
        // プラン期間
        _buildPeriodInfo(context, textTheme, colorScheme),
      ],
    );
  }

  Widget _buildUsageInfo(
    BuildContext context,
    TextTheme textTheme,
    ColorScheme colorScheme,
  ) {
    final currentPlan = team.teamPlan;
    final planMaxBalls = currentPlan?.plan?.maxBalls ?? 0;
    final planBallUsage = currentPlan?.currentUsage ?? 0;
    final itemBallUsage = team.item?.ballUsage ?? 0;
    final itemBallAvailable = team.item?.ballAvailableCount ?? 0;

    final planMaxAiCoach = currentPlan?.plan?.maxAiCoachs ?? 0;
    final planAiCoachUsage = currentPlan?.currentAiCoachUsage ?? 0;
    final itemAiCoachUsage = team.item?.aiCoachUsage ?? 0;
    final itemAiCoachAvailable = team.item?.aiCoachAvailableCount ?? 0;

    final nextPlanMaxBalls = team.nextTeamPlan?.plan?.maxBalls ?? 0;
    final nextPlanMaxAiCoach = team.nextTeamPlan?.plan?.maxAiCoachs ?? 0;

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Text(
          context.l10n.super_admin_team_item__usage,
          style: textTheme.titleSmall,
        ),
        const Gap(8),
        // ボール解析
        Text(
          context.l10n.super_admin_team_item__ball_analysis,
          style: textTheme.bodySmall?.copyWith(
            fontWeight: FontWeight.bold,
          ),
        ),
        const Gap(4),
        Padding(
          padding: const EdgeInsets.only(left: 16),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Text(
                'Subscription: ${currentPlan != null ? '$planBallUsage/$planMaxBalls' : '-'}',
                style: textTheme.bodySmall?.copyWith(
                  color: colorScheme.onSurfaceVariant,
                ),
              ),
              const Gap(2),
              Text(
                'Item: ${team.item != null ? '$itemBallUsage/$itemBallAvailable' : '-'}',
                style: textTheme.bodySmall?.copyWith(
                  color: colorScheme.onSurfaceVariant,
                ),
              ),
              if (team.nextTeamPlan != null) ...[
                const Gap(4),
                Text(
                  '${context.l10n.super_admin_team_item__next_plan}: $nextPlanMaxBalls',
                  style: textTheme.bodySmall?.copyWith(
                    color: colorScheme.secondary,
                  ),
                ),
              ],
            ],
          ),
        ),
        const Gap(8),
        // AIコーチ
        Text(
          context.l10n.super_admin_team_item__ai_coach,
          style: textTheme.bodySmall?.copyWith(
            fontWeight: FontWeight.bold,
          ),
        ),
        const Gap(4),
        Padding(
          padding: const EdgeInsets.only(left: 16),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Text(
                'Subscription: ${currentPlan != null ? '$planAiCoachUsage/$planMaxAiCoach' : '-'}',
                style: textTheme.bodySmall?.copyWith(
                  color: colorScheme.onSurfaceVariant,
                ),
              ),
              const Gap(2),
              Text(
                'Item: ${team.item != null ? '$itemAiCoachUsage/$itemAiCoachAvailable' : '-'}',
                style: textTheme.bodySmall?.copyWith(
                  color: colorScheme.onSurfaceVariant,
                ),
              ),
              if (team.nextTeamPlan != null) ...[
                const Gap(4),
                Text(
                  '${context.l10n.super_admin_team_item__next_plan}: $nextPlanMaxAiCoach',
                  style: textTheme.bodySmall?.copyWith(
                    color: colorScheme.secondary,
                  ),
                ),
              ],
            ],
          ),
        ),
      ],
    );
  }

  Widget _buildPeriodInfo(
    BuildContext context,
    TextTheme textTheme,
    ColorScheme colorScheme,
  ) {
    final dateFormat = DateFormat('yyyy/MM/dd');
    final startDate = team.teamPlan?.startDate;
    final endDate = team.teamPlan?.endDate;
    final nextStartDate = team.nextTeamPlan?.startDate;
    final nextEndDate = team.nextTeamPlan?.endDate;

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Text(
          context.l10n.super_admin_team_item__period,
          style: textTheme.titleSmall,
        ),
        const Gap(4),
        Text(
          startDate != null ? dateFormat.format(startDate) : '-',
          style: textTheme.bodySmall?.copyWith(
            color: colorScheme.onSurfaceVariant,
          ),
        ),
        Text(
          '/ ${endDate != null ? dateFormat.format(endDate) : '-'}',
          style: textTheme.bodySmall?.copyWith(
            color: colorScheme.onSurfaceVariant,
          ),
        ),
        if (team.nextTeamPlan != null) ...[
          const Gap(4),
          Text(
            context.l10n.super_admin_team_item__next_plan,
            style: textTheme.bodySmall?.copyWith(
              color: colorScheme.secondary,
            ),
          ),
          Text(
            nextStartDate != null ? dateFormat.format(nextStartDate) : '-',
            style: textTheme.bodySmall?.copyWith(
              color: colorScheme.secondary,
            ),
          ),
          Text(
            '/ ${nextEndDate != null ? dateFormat.format(nextEndDate) : '-'}',
            style: textTheme.bodySmall?.copyWith(
              color: colorScheme.secondary,
            ),
          ),
        ],
      ],
    );
  }
}

